import { Racquet, PerformanceCategory, Brand } from '../types';

export interface AnalyticsStats {
  mean: number;
  median: number;
  std: number;
  min: number;
  max: number;
  count: number;
  percentiles: {
    p25: number;
    p75: number;
    p90: number;
    p95: number;
  };
}

export interface CategoryStats {
  category: string;
  stats: AnalyticsStats;
}

export interface BrandAnalytics {
  brand: string;
  count: number;
  avgRating: number;
  avgWeight: number;
  avgHeadSize: number;
  avgFlex: number;
  avgSwingweight: number;
  performanceProfile: Record<string, number>;
}

export interface DataQualityMetrics {
  totalRacquets: number;
  totalReviews: number;
  averageReviewsPerRacquet: number;
  completenessScores: {
    physicalSpecs: number;
    performanceRatings: number;
    overall: number;
  };
  dataDistribution: {
    brands: Array<{ name: string; count: number; percentage: number }>;
    weightRanges: Array<{ range: string; count: number; percentage: number }>;
    headSizeRanges: Array<{ range: string; count: number; percentage: number }>;
  };
}

export interface TrendData {
  category: string;
  data: Array<{
    brand: string;
    value: number;
    count: number;
  }>;
}

export class AnalyticsCalculator {
  private racquets: Racquet[];

  constructor(racquets: Racquet[]) {
    this.racquets = racquets;
  }

  // Basic statistical calculations
  static calculateStats(values: number[]): AnalyticsStats {
    if (values.length === 0) {
      return {
        mean: 0,
        median: 0,
        std: 0,
        min: 0,
        max: 0,
        count: 0,
        percentiles: { p25: 0, p75: 0, p90: 0, p95: 0 }
      };
    }

    const sorted = values.slice().sort((a, b) => a - b);
    const mean = values.reduce((sum, val) => sum + val, 0) / values.length;
    const variance = values.reduce((sum, val) => sum + Math.pow(val - mean, 2), 0) / values.length;
    const std = Math.sqrt(variance);

    return {
      mean: Number(mean.toFixed(2)),
      median: Number(AnalyticsCalculator.getPercentile(sorted, 50).toFixed(2)),
      std: Number(std.toFixed(2)),
      min: Number(sorted[0].toFixed(2)),
      max: Number(sorted[sorted.length - 1].toFixed(2)),
      count: values.length,
      percentiles: {
        p25: Number(AnalyticsCalculator.getPercentile(sorted, 25).toFixed(2)),
        p75: Number(AnalyticsCalculator.getPercentile(sorted, 75).toFixed(2)),
        p90: Number(AnalyticsCalculator.getPercentile(sorted, 90).toFixed(2)),
        p95: Number(AnalyticsCalculator.getPercentile(sorted, 95).toFixed(2))
      }
    };
  }

  static getPercentile(sortedArray: number[], percentile: number): number {
    const index = (percentile / 100) * (sortedArray.length - 1);
    if (Math.floor(index) === index) {
      return sortedArray[index];
    }
    const lower = Math.floor(index);
    const upper = Math.ceil(index);
    const weight = index - lower;
    return sortedArray[lower] * (1 - weight) + sortedArray[upper] * weight;
  }

  // Performance category statistics
  getPerformanceCategoryStats(): CategoryStats[] {
    const performanceCategories = [
      { key: 'power_avg', name: 'Power' },
      { key: 'control_avg', name: 'Control' },
      { key: 'comfort_avg', name: 'Comfort' },
      { key: 'maneuverability_avg', name: 'Maneuverability' },
      { key: 'stability_avg', name: 'Stability' },
      { key: 'serves_avg', name: 'Serves' },
      { key: 'returns_avg', name: 'Returns' },
      { key: 'groundstrokes_avg', name: 'Groundstrokes' },
      { key: 'volleys_avg', name: 'Volleys' },
      { key: 'slice_avg', name: 'Slice' },
      { key: 'topspin_avg', name: 'Topspin' },
      { key: 'touch_feel_avg', name: 'Touch/Feel' },
      { key: 'overall_avg', name: 'Overall' }
    ];

    return performanceCategories.map(category => {
      const values = this.racquets
        .map(r => r[category.key as keyof Racquet] as number)
        .filter(val => val !== undefined && val !== null && !isNaN(val));

      return {
        category: category.name,
        stats: AnalyticsCalculator.calculateStats(values)
      };
    });
  }

  // Physical specifications statistics
  getPhysicalSpecStats(): CategoryStats[] {
    const physicalSpecs = [
      { key: 'weight_oz', name: 'Weight (oz)' },
      { key: 'head_size_sq_in', name: 'Head Size (sq in)' },
      { key: 'flex', name: 'Flex Rating' },
      { key: 'swingweight', name: 'Swingweight' },
      { key: 'length_in', name: 'Length (in)' },
      { key: 'balance_pts', name: 'Balance (pts)' }
    ];

    return physicalSpecs.map(spec => {
      const values = this.racquets
        .map(r => r[spec.key as keyof Racquet] as number)
        .filter(val => val !== undefined && val !== null && !isNaN(val));

      return {
        category: spec.name,
        stats: AnalyticsCalculator.calculateStats(values)
      };
    });
  }

  // Brand analysis
  getBrandAnalytics(): BrandAnalytics[] {
    const brandGroups = this.racquets.reduce((acc, racquet) => {
      if (!acc[racquet.brand]) {
        acc[racquet.brand] = [];
      }
      acc[racquet.brand].push(racquet);
      return acc;
    }, {} as Record<string, Racquet[]>);

    return Object.entries(brandGroups).map(([brand, racquets]) => {
      const validRacquets = racquets.filter(r => r.overall_avg !== undefined);

      return {
        brand,
        count: racquets.length,
        avgRating: validRacquets.length > 0 
          ? Number((validRacquets.reduce((sum, r) => sum + (r.overall_avg || 0), 0) / validRacquets.length).toFixed(2))
          : 0,
        avgWeight: this.calculateBrandAverage(racquets, 'weight_oz'),
        avgHeadSize: this.calculateBrandAverage(racquets, 'head_size_sq_in'),
        avgFlex: this.calculateBrandAverage(racquets, 'flex'),
        avgSwingweight: this.calculateBrandAverage(racquets, 'swingweight'),
        performanceProfile: {
          power: this.calculateBrandAverage(racquets, 'power_avg'),
          control: this.calculateBrandAverage(racquets, 'control_avg'),
          comfort: this.calculateBrandAverage(racquets, 'comfort_avg'),
          maneuverability: this.calculateBrandAverage(racquets, 'maneuverability_avg'),
          stability: this.calculateBrandAverage(racquets, 'stability_avg')
        }
      };
    }).sort((a, b) => b.count - a.count);
  }

  private calculateBrandAverage(racquets: Racquet[], key: keyof Racquet): number {
    const values = racquets
      .map(r => r[key] as number)
      .filter(val => val !== undefined && val !== null && !isNaN(val));

    if (values.length === 0) return 0;
    return Number((values.reduce((sum, val) => sum + val, 0) / values.length).toFixed(2));
  }

  // Data quality metrics
  getDataQualityMetrics(): DataQualityMetrics {
    const totalRacquets = this.racquets.length;
    const totalReviews = this.racquets.reduce((sum, r) => sum + (r.review_count || 0), 0);

    // Calculate completeness scores
    const physicalSpecsComplete = this.racquets.filter(r => 
      r.weight_oz && r.head_size_sq_in && r.flex && r.swingweight
    ).length;

    const performanceRatingsComplete = this.racquets.filter(r => 
      r.overall_avg && r.power_avg && r.control_avg
    ).length;

    // Brand distribution
    const brandCounts = this.racquets.reduce((acc, r) => {
      acc[r.brand] = (acc[r.brand] || 0) + 1;
      return acc;
    }, {} as Record<string, number>);

    const brandDistribution = Object.entries(brandCounts)
      .map(([name, count]) => ({
        name,
        count,
        percentage: Number(((count / totalRacquets) * 100).toFixed(1))
      }))
      .sort((a, b) => b.count - a.count);

    // Weight ranges
    const weightRanges = this.getDistributionRanges(
      this.racquets.map(r => r.weight_oz).filter(w => w !== undefined) as number[],
      [0, 9.5, 10.5, 11.5, 12.5, 15],
      ['< 9.5 oz', '9.5-10.5 oz', '10.5-11.5 oz', '11.5-12.5 oz', '> 12.5 oz']
    );

    // Head size ranges
    const headSizeRanges = this.getDistributionRanges(
      this.racquets.map(r => r.head_size_sq_in).filter(h => h !== undefined) as number[],
      [0, 95, 100, 105, 110, 150],
      ['< 95 sq in', '95-100 sq in', '100-105 sq in', '105-110 sq in', '> 110 sq in']
    );

    return {
      totalRacquets,
      totalReviews,
      averageReviewsPerRacquet: totalReviews > 0 ? Number((totalReviews / totalRacquets).toFixed(1)) : 0,
      completenessScores: {
        physicalSpecs: Number(((physicalSpecsComplete / totalRacquets) * 100).toFixed(1)),
        performanceRatings: Number(((performanceRatingsComplete / totalRacquets) * 100).toFixed(1)),
        overall: Number((((physicalSpecsComplete + performanceRatingsComplete) / (totalRacquets * 2)) * 100).toFixed(1))
      },
      dataDistribution: {
        brands: brandDistribution,
        weightRanges,
        headSizeRanges
      }
    };
  }

  private getDistributionRanges(values: number[], ranges: number[], labels: string[]) {
    const total = values.length;
    const distribution = labels.map((label, i) => {
      const count = values.filter(val => {
        if (i === 0) return val < ranges[i + 1];
        if (i === labels.length - 1) return val >= ranges[i];
        return val >= ranges[i] && val < ranges[i + 1];
      }).length;

      return {
        range: label,
        count,
        percentage: total > 0 ? Number(((count / total) * 100).toFixed(1)) : 0
      };
    });

    return distribution;
  }

  // Trend data for charts
  getTrendData(): TrendData[] {
    const brandAnalytics = this.getBrandAnalytics();

    return [
      {
        category: 'Overall Rating by Brand',
        data: brandAnalytics.map(brand => ({
          brand: brand.brand,
          value: brand.avgRating,
          count: brand.count
        }))
      },
      {
        category: 'Average Weight by Brand',
        data: brandAnalytics.map(brand => ({
          brand: brand.brand,
          value: brand.avgWeight,
          count: brand.count
        }))
      },
      {
        category: 'Power vs Control by Brand',
        data: brandAnalytics.map(brand => ({
          brand: brand.brand,
          value: brand.performanceProfile.power - brand.performanceProfile.control,
          count: brand.count
        }))
      }
    ];
  }

  // Export summary for reporting
  getAnalyticsSummary() {
    return {
      performanceStats: this.getPerformanceCategoryStats(),
      physicalStats: this.getPhysicalSpecStats(),
      brandAnalytics: this.getBrandAnalytics(),
      dataQuality: this.getDataQualityMetrics(),
      trendData: this.getTrendData()
    };
  }
}

