import { useState, useEffect, useMemo } from 'react';
import { Racquet } from '../types';
import { 
  AnalyticsCalculator, 
  CategoryStats, 
  BrandAnalytics, 
  DataQualityMetrics, 
  TrendData 
} from '../utils/analytics-calculations';

export interface AnalyticsState {
  performanceStats: CategoryStats[];
  physicalStats: CategoryStats[];
  brandAnalytics: BrandAnalytics[];
  dataQuality: DataQualityMetrics;
  trendData: TrendData[];
  isLoading: boolean;
  error: string | null;
}

export interface AnalyticsFilters {
  selectedBrands: string[];
  performanceCategory: string;
  sortBy: 'count' | 'rating' | 'name';
  sortOrder: 'asc' | 'desc';
}

export interface UseAnalyticsProps {
  racquets: Racquet[];
  filters?: Partial<AnalyticsFilters>;
}

export const useAnalytics = ({ racquets, filters = {} }: UseAnalyticsProps) => {
  const [state, setState] = useState<AnalyticsState>({
    performanceStats: [],
    physicalStats: [],
    brandAnalytics: [],
    dataQuality: {
      totalRacquets: 0,
      totalReviews: 0,
      averageReviewsPerRacquet: 0,
      completenessScores: {
        physicalSpecs: 0,
        performanceRatings: 0,
        overall: 0
      },
      dataDistribution: {
        brands: [],
        weightRanges: [],
        headSizeRanges: []
      }
    },
    trendData: [],
    isLoading: true,
    error: null
  });

  const [analyticsFilters, setAnalyticsFilters] = useState<AnalyticsFilters>({
    selectedBrands: [],
    performanceCategory: 'overall_avg',
    sortBy: 'count',
    sortOrder: 'desc',
    ...filters
  });

  // Filter racquets based on analytics filters
  const filteredRacquets = useMemo(() => {
    let filtered = racquets;

    // Filter by selected brands
    if (analyticsFilters.selectedBrands.length > 0) {
      filtered = filtered.filter(racquet => 
        analyticsFilters.selectedBrands.includes(racquet.brand)
      );
    }

    return filtered;
  }, [racquets, analyticsFilters]);

  // Calculate analytics data
  const analyticsData = useMemo(() => {
    if (filteredRacquets.length === 0) {
      return null;
    }

    try {
      const calculator = new AnalyticsCalculator(filteredRacquets);
      return calculator.getAnalyticsSummary();
    } catch (error) {
      console.error('Error calculating analytics:', error);
      return null;
    }
  }, [filteredRacquets]);

  // Update state when analytics data changes
  useEffect(() => {
    if (analyticsData) {
      setState(prev => ({
        ...prev,
        performanceStats: analyticsData.performanceStats,
        physicalStats: analyticsData.physicalStats,
        brandAnalytics: sortBrandAnalytics(analyticsData.brandAnalytics, analyticsFilters),
        dataQuality: analyticsData.dataQuality,
        trendData: analyticsData.trendData,
        isLoading: false,
        error: null
      }));
    } else if (filteredRacquets.length === 0) {
      setState(prev => ({
        ...prev,
        isLoading: false,
        error: 'No racquets match the current filters'
      }));
    }
  }, [analyticsData, filteredRacquets.length, analyticsFilters]);

  // Sort brand analytics based on current filters
  const sortBrandAnalytics = (brands: BrandAnalytics[], filters: AnalyticsFilters): BrandAnalytics[] => {
    const sorted = [...brands].sort((a, b) => {
      let aValue: number;
      let bValue: number;

      switch (filters.sortBy) {
        case 'count':
          aValue = a.count;
          bValue = b.count;
          break;
        case 'rating':
          aValue = a.avgRating;
          bValue = b.avgRating;
          break;
        case 'name':
          return filters.sortOrder === 'asc' 
            ? a.brand.localeCompare(b.brand)
            : b.brand.localeCompare(a.brand);
        default:
          aValue = a.count;
          bValue = b.count;
      }

      return filters.sortOrder === 'asc' ? aValue - bValue : bValue - aValue;
    });

    return sorted;
  };

  // Filter actions
  const updateFilters = (newFilters: Partial<AnalyticsFilters>) => {
    setAnalyticsFilters(prev => ({
      ...prev,
      ...newFilters
    }));
  };

  const resetFilters = () => {
    setAnalyticsFilters({
      selectedBrands: [],
      performanceCategory: 'overall_avg',
      sortBy: 'count',
      sortOrder: 'desc'
    });
  };

  const toggleBrand = (brand: string) => {
    setAnalyticsFilters(prev => ({
      ...prev,
      selectedBrands: prev.selectedBrands.includes(brand)
        ? prev.selectedBrands.filter(b => b !== brand)
        : [...prev.selectedBrands, brand]
    }));
  };

  // Get top performing racquets in a category
  const getTopPerformers = (category: keyof Racquet, limit: number = 5) => {
    return filteredRacquets
      .filter(racquet => racquet[category] !== undefined)
      .sort((a, b) => (b[category] as number) - (a[category] as number))
      .slice(0, limit);
  };

  // Get category insights
  const getCategoryInsights = (category: string) => {
    const stats = state.performanceStats.find(stat => stat.category === category);
    if (!stats) return null;

    const topRacquets = getTopPerformers(category.toLowerCase().replace('/', '_').replace(' ', '_') + '_avg' as keyof Racquet, 3);
    const categoryKey = category.toLowerCase().replace('/', '_').replace(' ', '_') + '_avg';

    return {
      stats: stats.stats,
      topRacquets,
      insights: {
        highPerformers: topRacquets.length,
        averageScore: stats.stats.mean,
        scoringRange: stats.stats.max - stats.stats.min,
        consistency: stats.stats.std
      }
    };
  };

  // Get brand comparison data
  const getBrandComparison = (category: keyof BrandAnalytics['performanceProfile']) => {
    return state.brandAnalytics.map(brand => ({
      brand: brand.brand,
      value: brand.performanceProfile[category],
      count: brand.count,
      avgRating: brand.avgRating
    })).sort((a, b) => b.value - a.value);
  };

  // Export analytics data
  const exportData = () => {
    const exportData = {
      summary: {
        totalRacquets: state.dataQuality.totalRacquets,
        totalReviews: state.dataQuality.totalReviews,
        averageReviewsPerRacquet: state.dataQuality.averageReviewsPerRacquet,
        filtersApplied: analyticsFilters
      },
      performanceStats: state.performanceStats,
      physicalStats: state.physicalStats,
      brandAnalytics: state.brandAnalytics,
      dataQuality: state.dataQuality,
      generatedAt: new Date().toISOString()
    };

    const blob = new Blob([JSON.stringify(exportData, null, 2)], {
      type: 'application/json'
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `tennis-racquet-analytics-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return {
    // State
    ...state,

    // Filters
    filters: analyticsFilters,
    filteredRacquets,

    // Actions
    updateFilters,
    resetFilters,
    toggleBrand,

    // Utility functions
    getTopPerformers,
    getCategoryInsights,
    getBrandComparison,
    exportData,

    // Computed values
    hasData: filteredRacquets.length > 0,
    availableBrands: Array.from(new Set(racquets.map(r => r.brand))).sort()
  };
};

