'use client';

import React from 'react';
import { Card } from '../ui/Card';
import { AnalyticsStats } from '../../lib/utils/analytics-calculations';

export interface StatsCardProps {
  title: string;
  stats: AnalyticsStats;
  unit?: string;
  showPercentiles?: boolean;
  colorScheme?: 'blue' | 'green' | 'purple' | 'orange' | 'red';
  className?: string;
}

const colorSchemes = {
  blue: {
    bg: 'bg-blue-50',
    border: 'border-blue-200',
    text: 'text-blue-900',
    accent: 'text-blue-600',
    icon: 'text-blue-500'
  },
  green: {
    bg: 'bg-green-50',
    border: 'border-green-200',
    text: 'text-green-900',
    accent: 'text-green-600',
    icon: 'text-green-500'
  },
  purple: {
    bg: 'bg-purple-50',
    border: 'border-purple-200',
    text: 'text-purple-900',
    accent: 'text-purple-600',
    icon: 'text-purple-500'
  },
  orange: {
    bg: 'bg-orange-50',
    border: 'border-orange-200',
    text: 'text-orange-900',
    accent: 'text-orange-600',
    icon: 'text-orange-500'
  },
  red: {
    bg: 'bg-red-50',
    border: 'border-red-200',
    text: 'text-red-900',
    accent: 'text-red-600',
    icon: 'text-red-500'
  }
};

export const StatsCard: React.FC<StatsCardProps> = ({
  title,
  stats,
  unit = '',
  showPercentiles = false,
  colorScheme = 'blue',
  className = ''
}) => {
  const colors = colorSchemes[colorScheme];

  const formatValue = (value: number) => {
    if (value % 1 === 0) {
      return value.toString();
    }
    return value.toFixed(2);
  };

  const formatValueWithUnit = (value: number) => {
    return `${formatValue(value)}${unit}`;
  };

  if (stats.count === 0) {
    return (
      <Card className={`${colors.bg} ${colors.border} ${className}`}>
        <div className="p-6">
          <h3 className={`text-sm font-medium ${colors.text} mb-2`}>
            {title}
          </h3>
          <p className={`text-sm ${colors.accent}`}>
            No data available
          </p>
        </div>
      </Card>
    );
  }

  return (
    <Card className={`${colors.bg} ${colors.border} ${className}`}>
      <div className="p-6">
        {/* Header */}
        <div className="flex items-center justify-between mb-4">
          <h3 className={`text-sm font-medium ${colors.text}`}>
            {title}
          </h3>
          <span className={`text-xs ${colors.accent} bg-white px-2 py-1 rounded-full`}>
            n = {stats.count}
          </span>
        </div>

        {/* Main Statistics */}
        <div className="grid grid-cols-2 gap-4 mb-4">
          <div>
            <div className={`text-2xl font-bold ${colors.text}`}>
              {formatValueWithUnit(stats.mean)}
            </div>
            <div className={`text-xs ${colors.accent}`}>
              Mean
            </div>
          </div>
          <div>
            <div className={`text-2xl font-bold ${colors.text}`}>
              {formatValueWithUnit(stats.median)}
            </div>
            <div className={`text-xs ${colors.accent}`}>
              Median
            </div>
          </div>
        </div>

        {/* Range and Std Dev */}
        <div className="grid grid-cols-2 gap-4 mb-4">
          <div>
            <div className={`text-sm font-semibold ${colors.text}`}>
              {formatValueWithUnit(stats.min)} - {formatValueWithUnit(stats.max)}
            </div>
            <div className={`text-xs ${colors.accent}`}>
              Range
            </div>
          </div>
          <div>
            <div className={`text-sm font-semibold ${colors.text}`}>
              ±{formatValueWithUnit(stats.std)}
            </div>
            <div className={`text-xs ${colors.accent}`}>
              Std Dev
            </div>
          </div>
        </div>

        {/* Percentiles (optional) */}
        {showPercentiles && (
          <div className="border-t border-white pt-4">
            <div className={`text-xs font-medium ${colors.text} mb-2`}>
              Percentiles
            </div>
            <div className="grid grid-cols-2 gap-2 text-xs">
              <div className="flex justify-between">
                <span className={colors.accent}>25th:</span>
                <span className={colors.text}>{formatValueWithUnit(stats.percentiles.p25)}</span>
              </div>
              <div className="flex justify-between">
                <span className={colors.accent}>75th:</span>
                <span className={colors.text}>{formatValueWithUnit(stats.percentiles.p75)}</span>
              </div>
              <div className="flex justify-between">
                <span className={colors.accent}>90th:</span>
                <span className={colors.text}>{formatValueWithUnit(stats.percentiles.p90)}</span>
              </div>
              <div className="flex justify-between">
                <span className={colors.accent}>95th:</span>
                <span className={colors.text}>{formatValueWithUnit(stats.percentiles.p95)}</span>
              </div>
            </div>
          </div>
        )}

        {/* Distribution Indicator */}
