'use client';

import React, { useMemo } from 'react';
import { Card } from '../ui/Card';

export interface TrendDataPoint {
  brand: string;
  value: number;
  count: number;
}

export interface TrendChartProps {
  title: string;
  data: TrendDataPoint[];
  valueLabel?: string;
  unit?: string;
  colorScheme?: 'blue' | 'green' | 'purple' | 'orange' | 'red';
  showCount?: boolean;
  maxBars?: number;
  className?: string;
}

const colorSchemes = {
  blue: {
    bg: 'bg-blue-50',
    border: 'border-blue-200',
    text: 'text-blue-900',
    accent: 'text-blue-600',
    bar: 'bg-blue-500',
    barLight: 'bg-blue-200'
  },
  green: {
    bg: 'bg-green-50',
    border: 'border-green-200',
    text: 'text-green-900',
    accent: 'text-green-600',
    bar: 'bg-green-500',
    barLight: 'bg-green-200'
  },
  purple: {
    bg: 'bg-purple-50',
    border: 'border-purple-200',
    text: 'text-purple-900',
    accent: 'text-purple-600',
    bar: 'bg-purple-500',
    barLight: 'bg-purple-200'
  },
  orange: {
    bg: 'bg-orange-50',
    border: 'border-orange-200',
    text: 'text-orange-900',
    accent: 'text-orange-600',
    bar: 'bg-orange-500',
    barLight: 'bg-orange-200'
  },
  red: {
    bg: 'bg-red-50',
    border: 'border-red-200',
    text: 'text-red-900',
    accent: 'text-red-600',
    bar: 'bg-red-500',
    barLight: 'bg-red-200'
  }
};

export const TrendChart: React.FC<TrendChartProps> = ({
  title,
  data,
  valueLabel = 'Value',
  unit = '',
  colorScheme = 'blue',
  showCount = true,
  maxBars = 10,
  className = ''
}) => {
  const colors = colorSchemes[colorScheme];

  const processedData = useMemo(() => {
    if (!data || data.length === 0) return [];

    // Sort and limit data
    const sorted = [...data]
      .filter(d => d.value !== 0 && !isNaN(d.value))
      .sort((a, b) => b.value - a.value)
      .slice(0, maxBars);

    if (sorted.length === 0) return [];

    const maxValue = Math.max(...sorted.map(d => d.value));
    const minValue = Math.min(...sorted.map(d => d.value));
    const range = maxValue - minValue;

    return sorted.map(item => ({
      ...item,
      percentage: range > 0 ? ((item.value - minValue) / range * 80) + 20 : 50 // 20-100% range
    }));
  }, [data, maxBars]);

  const formatValue = (value: number) => {
    if (Math.abs(value) < 0.01) return '0';
    if (Math.abs(value) < 0.1) return value.toFixed(3);
    if (Math.abs(value) < 1) return value.toFixed(2);
    if (Math.abs(value) < 10) return value.toFixed(1);
    return Math.round(value).toString();
  };

  const formatValueWithUnit = (value: number) => {
    return `${formatValue(value)}${unit}`;
  };

  if (processedData.length === 0) {
    return (
      <Card className={`${colors.bg} ${colors.border} ${className}`}>
        <div className="p-6">
          <h3 className={`text-lg font-semibold ${colors.text} mb-4`}>
            {title}
          </h3>
          <p className={`text-sm ${colors.accent}`}>
            No data available for visualization
          </p>
        </div>
      </Card>
    );
  }

  const topValue = processedData[0]?.value || 0;
  const bottomValue = processedData[processedData.length - 1]?.value || 0;

  return (
    <Card className={`${colors.bg} ${colors.border} ${className}`}>
      <div className="p-6">
        {/* Header */}
        <div className="flex items-center justify-between mb-6">
          <h3 className={`text-lg font-semibold ${colors.text}`}>
            {title}
          </h3>
          <div className={`text-sm ${colors.accent}`}>
            {valueLabel}
          </div>
        </div>

        {/* Summary Stats */}
        <div className="grid grid-cols-3 gap-4 mb-6 text-center">
          <div>
            <div className={`text-lg font-bold ${colors.text}`}>
              {formatValueWithUnit(topValue)}
            </div>
            <div className={`text-xs ${colors.accent}`}>
              Highest
            </div>
          </div>
          <div>
            <div className={`text-lg font-bold ${colors.text}`}>
              {formatValueWithUnit((topValue + bottomValue) / 2)}
            </div>
            <div className={`text-xs ${colors.accent}`}>
              Average
            </div>
          </div>
          <div>
            <div className={`text-lg font-bold ${colors.text}`}>
              {formatValueWithUnit(bottomValue)}
            </div>
            <div className={`text-xs ${colors.accent}`}>
              Lowest
            </div>
          </div>
        </div>

        {/* Chart */}
        <div className="space-y-3">
          {processedData.map((item, index) => (
            <div key={item.brand} className="relative">
              {/* Brand name and value */}
              <div className="flex items-center justify-between mb-1">
                <span className={`text-sm font-medium ${colors.text} truncate flex-1 mr-2`}>
                  {item.brand}
                </span>
                <div className="flex items-center space-x-2 text-sm">
                  <span className={`font-semibold ${colors.text}`}>
                    {formatValueWithUnit(item.value)}
                  </span>
                  {showCount && (
                    <span className={`${colors.accent} text-xs`}>
                      ({item.count})
                    </span>
                  )}
                </div>
              </div>

              {/* Bar */}
              <div className="relative">
                <div className={`h-2 ${colors.barLight} rounded-full`}>
                  <div 
                    className={`h-full ${colors.bar} rounded-full transition-all duration-500 ease-out`}
                    style={{ width: `${item.percentage}%` }}
                  />
                </div>

                {/* Rank indicator */}
                <div className={`absolute -left-1 -top-1 w-4 h-4 ${colors.bar} rounded-full flex items-center justify-center text-white text-xs font-bold`}>
                  {index + 1}
                </div>
              </div>
            </div>
          ))}
        </div>

        {/* Legend */}
        {showCount && (
          <div className="mt-4 pt-4 border-t border-white">
            <div className={`text-xs ${colors.accent} text-center`}>
              Numbers in parentheses show racquet count per brand
            </div>
          </div>
        )}
      </div>
    </Card>
  );
};

export default TrendChart;

