import { useState, useEffect, useMemo } from 'react';
import { Racquet } from '../types';
import { 
  AnalyticsCalculator, 
  CategoryStats, 
  BrandAnalytics, 
  DataQualityMetrics, 
  TrendData 
} from '../utils/analytics-calculations';

export interface AnalyticsState {
  performanceStats: CategoryStats[];
  physicalStats: CategoryStats[];
  brandAnalytics: BrandAnalytics[];
  dataQuality: DataQualityMetrics;
  trendData: TrendData[];
  isLoading: boolean;
  error: string | null;
}

export interface AnalyticsFilters {
  selectedBrands: string[];
  performanceCategory: string;
  sortBy: 'count' | 'rating' | 'name';
  sortOrder: 'asc' | 'desc';
}

export interface UseAnalyticsProps {
  racquets: Racquet[];
  filters?: Partial<AnalyticsFilters>;
}

export const useAnalytics = ({ racquets, filters = {} }: UseAnalyticsProps) => {
  const [state, setState] = useState<AnalyticsState>({
    performanceStats: [],
    physicalStats: [],
    brandAnalytics: [],
    dataQuality: {
      totalRacquets: 0,
      totalReviews: 0,
      averageReviewsPerRacquet: 0,
      completenessScores: {
        physicalSpecs: 0,
        performanceRatings: 0,
        overall: 0
      },
      dataDistribution: {
        brands: [],
        weightRanges: [],
        headSizeRanges: []
      }
    },
    trendData: [],
    isLoading: true,
    error: null
  });

  const [analyticsFilters, setAnalyticsFilters] = useState<AnalyticsFilters>({
    selectedBrands: [],
    performanceCategory: 'overall_avg',
    sortBy: 'count',
    sortOrder: 'desc',
    ...filters
  });

  // Filter racquets based on analytics filters
  const filteredRacquets = useMemo(() => {
    let filtered = racquets;

    // Filter by selected brands
    if (analyticsFilters.selectedBrands.length > 0) {
      filtered = filtered.filter(racquet => 
        analyticsFilters.selectedBrands.includes(racquet.brand)
      );
    }

    return filtered;
  }, [racquets, analyticsFilters]);

  // Calculate analytics data
  const analyticsData = useMemo(() => {
    if (filteredRacquets.length === 0) {
      return null;
    }

    try {
      const calculator = new AnalyticsCalculator(filteredRacquets);
      return calculator.getAnalyticsSummary();
    } catch (error) {
      console.error('Error calculating analytics:', error);
      return null;
    }
  }, [filteredRacquets]);

  // Update state when analytics data changes
  useEffect(() => {
    if (analyticsData) {
      setState(prev => ({
        ...prev,
        performanceStats: analyticsData.performanceStats,
        physicalStats: analyticsData.physicalStats,
        brandAnalytics: sortBrandAnalytics(analyticsData.brandAnalytics, analyticsFilters),
        dataQuality: analyticsData.dataQuality,
        trendData: analyticsData.trendData,
        isLoading: false,
        error: null
      }));
    } else if (filteredRacquets.length === 0) {
      setState(prev => ({
        ...prev,
        isLoading: false,
        error: 'No racquets match the current filters'
      }));
    }
  }, [analyticsData, filteredRacquets.length, analyticsFilters]);

  // Sort brand analytics based on current filters
  const sortBrandAnalytics = (brands: BrandAnalytics[], filters: AnalyticsFilters): BrandAnalytics[] => {
    const sorted = [...brands].sort((a, b) => {
      let aValue: number;
      let bValue: number;

      switch (filters.sortBy) {
        case 'count':
          aValue = a.count;
          bValue = b.count;
          break;
        case 'rating':
          aValue = a.avgRating;
          bValue = b.avgRating;
          break;
        case 'name':
          return filters.sortOrder === 'asc' 
            ? a.brand.localeCompare(b.brand)
            : b.brand.localeCompare(a.brand);
        default:
          aValue = a.count;
          bValue = b.count;
      }

      return filters.sortOrder === 'asc' ? aValue - bValue : bValue - aValue;
    });

    return sorted;
  };

  // Filter actions
  const updateFilters = (newFilters: Partial<AnalyticsFilters>) => {
    setAnalyticsFilters(prev => ({
      ...prev,
      ...newFilters
    }));
  };

  const resetFilters = () => {
    setAnalyticsFilters({
      selectedBrands: [],
      performanceCategory: 'overall_avg',
      sortBy: 'count',
      sortOrder: 'desc'
    });
  };

  const toggleBrand = (brand: string) => {
    setAnalyticsFilters(prev => ({
      ...prev,
      selectedBrands: prev.selectedBrands.includes(brand)
        ? prev.selectedBrands.filter(b => b !== brand)
        : [...prev.selectedBrands, brand]
    }));
  };

  // Get top performing racquets in a category
  const getTopPerformers = (category: keyof Racquet, limit: number = 5) => {
    return filteredRacquets
      .filter(racquet => racquet[category] !== undefined)
      .sort((a, b) => (b[category] as number) - (a[category] as number))
      .slice(0, limit);
  };

  // Get category insights
  const getCategoryInsights = (category: string) => {
    const stats = state.performanceStats.find(stat => stat.category === category);
    if (!stats) return null;

    const topRacquets = getTopPerformers(category.toLowerCase().replace('/', '_').replace(' ', '_') + '_avg' as keyof Racquet, 3);
    const categoryKey = category.toLowerCase().replace('/', '_').replace(' ', '_') + '_avg';

    return {
      stats: stats.stats,
      topRacquets,
      insights: {
        highPerformers: topRacquets.length,
        averageScore: stats.stats.mean,
        scoringRange: stats.stats.max - stats.stats.min,
        consistency: stats.stats.std
      }
    };
  };

  // Get brand comparison data
  const getBrandComparison = (category: keyof BrandAnalytics['performanceProfile']) => {
    return state.brandAnalytics.map(brand => ({
      brand: brand.brand,
      value: brand.performanceProfile[category],
      count: brand.count,
      avgRating: brand.avgRating
    })).sort((a, b) => b.value - a.value);
  };

  // Export analytics data
  const exportData = () => {
    const exportData = {
      summary: {
        totalRacquets: state.dataQuality.totalRacquets,
        totalReviews: state.dataQuality.totalReviews,
        averageReviewsPerRacquet: state.dataQuality.averageReviewsPerRacquet,
        filtersApplied: analyticsFilters
      },
      performanceStats: state.performanceStats,
      physicalStats: state.physicalStats,
      brandAnalytics: state.brandAnalytics,
      dataQuality: state.dataQuality,
      generatedAt: new Date().toISOString()
    };

    const blob = new Blob([JSON.stringify(exportData, null, 2)], {
      type: 'application/json'
    });
    const url = URL.createObjectURL(blob);
    const a = document.createElement('a');
    a.href = url;
    a.download = `tennis-racquet-analytics-${new Date().toISOString().split('T')[0]}.json`;
    document.body.appendChild(a);
    a.click();
    document.body.removeChild(a);
    URL.revokeObjectURL(url);
  };

  return {
    // State
    ...state,

    // Filters
    filters: analyticsFilters,
    filteredRacquets,

    // Actions
    updateFilters,
    resetFilters,
    toggleBrand,

    // Utility functions
    getTopPerformers,
    getCategoryInsights,
    getBrandComparison,
    exportData,

    // Computed values
    hasData: filteredRacquets.length > 0,
    availableBrands: Array.from(new Set(racquets.map(r => r.brand))).sort()
  };
};

'use client';

import React, { useState } from 'react';
import { Racquet } from '../../lib/types';
import { useAnalytics } from '../../lib/hooks/useAnalytics';
import { StatsCard } from './StatsCard';
import { TrendChart } from './TrendChart';
import { Card } from '../ui/Card';
import { Button } from '../ui/Button';
import { Select } from '../ui/Select';
import { LoadingSpinner } from '../ui/LoadingSpinner';

export interface AnalyticsDashboardProps {
  racquets: Racquet[];
  className?: string;
}

export const AnalyticsDashboard: React.FC<AnalyticsDashboardProps> = ({
  racquets,
  className = ''
}) => {
  const [activeTab, setActiveTab] = useState<'performance' | 'physical' | 'brands' | 'quality'>('performance');

  const {
    performanceStats,
    physicalStats,
    brandAnalytics,
    dataQuality,
    trendData,
    isLoading,
    error,
    filters,
    updateFilters,
    resetFilters,
    toggleBrand,
    getBrandComparison,
    exportData,
    hasData,
    availableBrands
  } = useAnalytics({ racquets });

  if (isLoading) {
    return (
      <div className={`flex items-center justify-center p-12 ${className}`}>
        <LoadingSpinner size="lg" />
      </div>
    );
  }

  if (error || !hasData) {
    return (
      <Card className={className}>
        <div className="p-8 text-center">
          <h3 className="text-lg font-semibold text-gray-900 mb-2">
            No Analytics Data Available
          </h3>
          <p className="text-gray-600 mb-4">
            {error || 'No racquets match the current filters'}
          </p>
          {filters.selectedBrands.length > 0 && (
            <Button onClick={resetFilters} variant="outline">
              Clear Filters
            </Button>
          )}
        </div>
      </Card>
    );
  }

  const tabs = [
    { id: 'performance', label: 'Performance', icon: '📊' },
    { id: 'physical', label: 'Physical Specs', icon: '🏸' },
    { id: 'brands', label: 'Brand Analysis', icon: '🏷️' },
    { id: 'quality', label: 'Data Quality', icon: '📈' }
  ] as const;

  const handleSortChange = (value: string) => {
    const [sortBy, sortOrder] = value.split('-');
    updateFilters({
      sortBy: sortBy as 'count' | 'rating' | 'name',
      sortOrder: sortOrder as 'asc' | 'desc'
    });
  };

  const renderPerformanceTab = () => (
    <div className="space-y-6">
      {/* Performance Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {performanceStats.map((stat, index) => (
          <StatsCard
            key={stat.category}
            title={stat.category}
            stats={stat.stats}
            unit=""
            showPercentiles={false}
            colorScheme={
              index % 5 === 0 ? 'blue' :
              index % 5 === 1 ? 'green' :
              index % 5 === 2 ? 'purple' :
              index % 5 === 3 ? 'orange' : 'red'
            }
          />
        ))}
      </div>

      {/* Performance Trends */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <TrendChart
          title="Overall Rating by Brand"
          data={getBrandComparison('power')}
          valueLabel="Average Rating"
          unit="/10"
          colorScheme="blue"
          showCount={true}
        />
        <TrendChart
          title="Power vs Control Balance"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.performanceProfile.power - brand.performanceProfile.control,
            count: brand.count
          }))}
          valueLabel="Power - Control"
          unit=""
          colorScheme="purple"
          showCount={true}
        />
      </div>
    </div>
  );

  const renderPhysicalTab = () => (
    <div className="space-y-6">
      {/* Physical Stats Grid */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {physicalStats.map((stat, index) => (
          <StatsCard
            key={stat.category}
            title={stat.category}
            stats={stat.stats}
            unit={
              stat.category.includes('Weight') ? ' oz' :
              stat.category.includes('Head Size') ? ' sq in' :
              stat.category.includes('Length') ? '"' : ''
            }
            showPercentiles={true}
            colorScheme={
              index % 5 === 0 ? 'green' :
              index % 5 === 1 ? 'blue' :
              index % 5 === 2 ? 'orange' :
              index % 5 === 3 ? 'purple' : 'red'
            }
          />
        ))}
      </div>

      {/* Physical Specification Trends */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <TrendChart
          title="Average Weight by Brand"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.avgWeight,
            count: brand.count
          }))}
          valueLabel="Weight"
          unit=" oz"
          colorScheme="green"
          showCount={true}
        />
        <TrendChart
          title="Average Head Size by Brand"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.avgHeadSize,
            count: brand.count
          }))}
          valueLabel="Head Size"
          unit=" sq in"
          colorScheme="orange"
          showCount={true}
        />
      </div>
    </div>
  );

  const renderBrandsTab = () => (
    <div className="space-y-6">
      {/* Brand Control Panel */}
      <Card className="bg-gray-50 border-gray-200">
        <div className="p-4">
          <div className="flex flex-wrap items-center gap-4">
            <div className="flex-1 min-w-48">
              <label className="block text-sm font-medium text-gray-700 mb-1">
                Sort Brands By
              </label>
              <Select
                value={`${filters.sortBy}-${filters.sortOrder}`}
                onChange={handleSortChange}
                className="w-full"
              >
                <option value="count-desc">Most Racquets</option>
                <option value="count-asc">Fewest Racquets</option>
                <option value="rating-desc">Highest Rating</option>
                <option value="rating-asc">Lowest Rating</option>
                <option value="name-asc">Name A-Z</option>
                <option value="name-desc">Name Z-A</option>
              </Select>
            </div>

            <div className="flex items-end gap-2">
              <Button onClick={resetFilters} variant="outline" size="sm">
                Reset Filters
              </Button>
              <Button onClick={exportData} variant="primary" size="sm">
                Export Data
              </Button>
            </div>
          </div>
        </div>
      </Card>

      {/* Brand Analytics Cards */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-4">
        {brandAnalytics.slice(0, 12).map((brand, index) => (
          <Card 
            key={brand.brand}
            className={`cursor-pointer transition-all duration-200 ${
              filters.selectedBrands.includes(brand.brand)
                ? 'bg-blue-50 border-blue-300 shadow-md'
                : 'hover:shadow-md hover:border-gray-300'
            }`}
            onClick={() => toggleBrand(brand.brand)}
          >
            <div className="p-4">
              <div className="flex items-center justify-between mb-3">
                <h3 className="font-semibold text-gray-900 truncate">
                  {brand.brand}
                </h3>
                <span className="text-sm text-gray-500 bg-gray-100 px-2 py-1 rounded-full">
                  {brand.count} racquets
                </span>
              </div>

              <div className="grid grid-cols-2 gap-3 text-sm">
                <div>
                  <div className="font-medium text-gray-900">
                    {brand.avgRating.toFixed(1)}/10
                  </div>
                  <div className="text-gray-500">Avg Rating</div>
                </div>
                <div>
                  <div className="font-medium text-gray-900">
                    {brand.avgWeight.toFixed(1)} oz
                  </div>
                  <div className="text-gray-500">Avg Weight</div>
                </div>
              </div>

              <div className="mt-3 pt-3 border-t border-gray-200">
                <div className="flex justify-between text-xs text-gray-600">
                  <span>Power: {brand.performanceProfile.power.toFixed(1)}</span>
                  <span>Control: {brand.performanceProfile.control.toFixed(1)}</span>
                </div>
              </div>
            </div>
          </Card>
        ))}
      </div>

      {/* Brand Comparison Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <TrendChart
          title="Brand Market Share"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.count,
            count: brand.count
          }))}
          valueLabel="Racquet Count"
          unit=""
          colorScheme="blue"
          showCount={false}
        />
        <TrendChart
          title="Average Rating by Brand"
          data={brandAnalytics.map(brand => ({
            brand: brand.brand,
            value: brand.avgRating,
            count: brand.count
          }))}
          valueLabel="Rating"
          unit="/10"
          colorScheme="green"
          showCount={true}
        />
      </div>
    </div>
  );

  const renderQualityTab = () => (
    <div className="space-y-6">
      {/* Data Quality Overview */}
      <div className="grid grid-cols-1 md:grid-cols-3 gap-4">
        <Card className="bg-blue-50 border-blue-200">
          <div className="p-6 text-center">
            <div className="text-3xl font-bold text-blue-900 mb-2">
              {dataQuality.totalRacquets}
            </div>
            <div className="text-sm text-blue-600">Total Racquets</div>
          </div>
        </Card>

        <Card className="bg-green-50 border-green-200">
          <div className="p-6 text-center">
            <div className="text-3xl font-bold text-green-900 mb-2">
              {dataQuality.totalReviews.toLocaleString()}
            </div>
            <div className="text-sm text-green-600">Total Reviews</div>
          </div>
        </Card>

        <Card className="bg-purple-50 border-purple-200">
          <div className="p-6 text-center">
            <div className="text-3xl font-bold text-purple-900 mb-2">
              {dataQuality.averageReviewsPerRacquet}
            </div>
            <div className="text-sm text-purple-600">Avg Reviews/Racquet</div>
          </div>
        </Card>
      </div>

      {/* Data Completeness */}
      <Card>
        <div className="p-6">
          <h3 className="text-lg font-semibold text-gray-900 mb-4">
            Data Completeness
          </h3>

          <div className="space-y-4">
            <div>
              <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-gray-700">
                  Physical Specifications
                </span>
                <span className="text-sm text-gray-600">
                  {dataQuality.completenessScores.physicalSpecs}%
                </span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div 
                  className="bg-blue-500 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${dataQuality.completenessScores.physicalSpecs}%` }}
                />
              </div>
            </div>

            <div>
              <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-gray-700">
                  Performance Ratings
                </span>
                <span className="text-sm text-gray-600">
                  {dataQuality.completenessScores.performanceRatings}%
                </span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div 
                  className="bg-green-500 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${dataQuality.completenessScores.performanceRatings}%` }}
                />
              </div>
            </div>

            <div>
              <div className="flex justify-between items-center mb-2">
                <span className="text-sm font-medium text-gray-700">
                  Overall Completeness
                </span>
                <span className="text-sm text-gray-600">
                  {dataQuality.completenessScores.overall}%
                </span>
              </div>
              <div className="w-full bg-gray-200 rounded-full h-2">
                <div 
                  className="bg-purple-500 h-2 rounded-full transition-all duration-300"
                  style={{ width: `${dataQuality.completenessScores.overall}%` }}
                />
              </div>
            </div>
          </div>
        </div>
      </Card>

      {/* Distribution Charts */}
      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <TrendChart
          title="Weight Distribution"
          data={dataQuality.dataDistribution.weightRanges.map(range => ({
            brand: range.range,
            value: range.percentage,
            count: range.count
          }))}
          valueLabel="Percentage"
          unit="%"
          colorScheme="orange"
          showCount={true}
          maxBars={8}
        />
        <TrendChart
          title="Head Size Distribution"
          data={dataQuality.dataDistribution.headSizeRanges.map(range => ({
            brand: range.range,
            value: range.percentage,
            count: range.count
          }))}
          valueLabel="Percentage"
          unit="%"
          colorScheme="red"
          showCount={true}
          maxBars={8}
        />
      </div>
    </div>
  );

  return (
    <div className={className}>
      {/* Header */}
      <div className="mb-6">
        <h2 className="text-2xl font-bold text-gray-900 mb-2">
          Performance Analytics Dashboard
        </h2>
        <p className="text-gray-600">
          Comprehensive insights into racquet performance, specifications, and market trends
        </p>
      </div>

      {/* Tab Navigation */}
      <div className="border-b border-gray-200 mb-6">
        <nav className="-mb-px flex space-x-8">
          {tabs.map((tab) => (
            <button
              key={tab.id}
              onClick={() => setActiveTab(tab.id)}
              className={`py-2 px-1 border-b-2 font-medium text-sm transition-colors duration-200 ${
                activeTab === tab.id
                  ? 'border-blue-500 text-blue-600'
                  : 'border-transparent text-gray-500 hover:text-gray-700 hover:border-gray-300'
              }`}
            >
              <span className="mr-2">{tab.icon}</span>
              {tab.label}
            </button>
          ))}
        </nav>
      </div>

      {/* Tab Content */}
      <div className="min-h-96">
        {activeTab === 'performance' && renderPerformanceTab()}
        {activeTab === 'physical' && renderPhysicalTab()}
        {activeTab === 'brands' && renderBrandsTab()}
        {activeTab === 'quality' && renderQualityTab()}
      </div>
    </div>
  );
};

export default AnalyticsDashboard;

